    with link = "point.de.Löhne-Westf-Pbf", railway = :station :single {
        let el = path("d3.de.1820");

        # DE 1820 dn - DE 2992 dn
        track(
                el[:loh.ae, :loh.xe - 4mo] << 0.5mo
            ..  hh[:loh.ye, :loh.xg] << 2.5mo
        );

        # DE 1700
        track(:double :casing,
                hh[:loh.ah, :loh.xe]
            ..  hh[:loh.ye, :loh.xg] << 1mo
        );

        # DE 1820 dn - DE 2992 up
        with layer = -1 track(
                el[:loh.xe - 311m, :loh.xe - 310m] << 0.5mo
            --  el[:loh.xe - 310m + 1dl, :loh.xe - 4mo] >> 0.5mo
            ..  hh[:loh.ye, :loh.xg] >> 0.5mo
        );

        # DE 2990
        track(:double :nopax, hh[:loh.ah, :loh.xg] >> 2mo);

        # DE 2993 dn
        track(:nopax :removed,
                hh[:loh.ye + 800m + 2dl, :loh + 1dl] >> 4.5mo
        );
        track(:nopax,
                hh[:loh - 0.1dl, :loh] >> 5.5mo
            --  hh[:loh + 1dl, :loh + 1.1dl] >> 4.5mo
            ..  hh[:loh.xg + 300m, :loh.xg + 301m] >> 5.5mo
        );

        # DE 2993 up
        track(:nopax,
                hh[:loh.ye + 799m, :loh.ye + 800m] >> 2.5mo
            --  hh[:loh.ye + 800m + 3dl, :loh + 1dl] >> 5.5mo
            ..  hh[:loh.xg + 300m, :loh.xg + 301m] >> 6.5mo
        );

        marker(:left :de.bf, hh[:loh] << 2.5mo << 0.5mt);
        station(:bottom, hh[:loh] << 2.5mo << 0.5mt << 1sh + (7dt, 1dt),
            hbox(:center:base, span(:bold, "Löhne "), "(Westf)",
                span(:bold, " Pbf")
            ),
            hbox(:center:top,
                vbox(:right:top,
                    span(:nopax, "2993: "),
                    span(:nopax, "2990: "),
                    "2992: ", "1700: ", "1820: "
                ),
                vbox(:sep:top,
                    hbox(:sep:base :nopax, "85,", anchor(), "295"),
                    hbox(:sep:base :nopax, "85,", anchor(), "303"),
                    hbox(:sep:base, "85,", anchor(), "295"),
                    hbox(:sep:base :nopax, "85,", anchor(), "275"),
                    hbox(:sep:base :nopax, "81,", anchor(), "975")
                )
            )
        );
    }

    with link = "point.de.Löhne-Westf-Gbf", railway = :station :single {
        let lr = path("d3.de.2992");

        # DE 2992 dn
        with layer = -1 track(
                hh[:loh.xg, :log - 500m] << 2.5mo
            ..  hh[:log, :log.yr] << 4mo
            ..  lr[:log.xr, :log.fr] << 0.5mo
