        # DE 1700
        track(:double :casing,
                hh[:loh.xg, :log - 500m] << 1mo
            ..  hh[:log, :log.yr] << 2mo
            ..  hh[:log.yh, :log.yh + 0.1dl]
        );

        # DE 2992 up
        with layer = -1 track(
                hh[:loh.xg, :log - 500m] >> 0.5mo
            ..  hh[:log, :log.yr]
            ..  lr[:log.xr, :log.fr] >> 0.5mo
        );

        # DE 2990
        track(:casing :double :nopax, hh[:loh.xg, :log.yh] >> 2mo);

        # DE 2993 dn
        track(:nopax,
                hh[:loh.xg + 300m, :log.yr - 1dl] >> 5.5mo
            --  hh[:log.yr, :log.yr + 0.1dl] >> 6.5mo
        );
        with layer = -1 track(:nopax :removed,
                hh[:log.yr - 0.1dl, :log.yr] >> 5.5mo
            ..  lr[:log.yg, :log.fr - 350m - 2.7dl] >> 1.5mo
            --  lr[:log.fr - 350m - 0.7dl, :log.fr - 350m - 0.69dl] << 0.5mo
        );   

        # DE 2993 up
        track(:nopax,
                hh[:loh.xg + 300m, :log.yr] >> 6.5mo
            ..  lr[:log.yg, :log.fr - 350m - 2dl] >> 2.5mo
            --  lr[:log.fr - 350m, :log.fr - 349m] >> 0.5mo
        );

        marker(:right :de.bft :nopax, hh[:log] >> 6.5mo >> 0.5mt);
        station(:top, hh[:log] >> 6.5mo >> 0.5mt >> 1sh + (-1dt, -1.3dt),
            hbox(:center:base :small,
                "Löhne ", span(:light, "(Westf)"), " Gbf"
            ),
            hbox(:center:top,
                vbox(:right:top,
                    span(:nopax, "2993: "),
                    span(:nopax, "2990: "),
                    "2992: ",
                    "1700: "
                ),
                vbox(:sep:top,
                    hbox(:sep:base :nopax, "87,", anchor(), "640"),
                    hbox(:sep:base :nopax, "86,", anchor(), "500"),
                    hbox(:sep:base, "87,", anchor(), "371"),
                    hbox(:sep:base, "86,", anchor(), "500")
                )
            )
        );
    }

